 364→            try { return new URL(h.url).hostname === hostname; } 
 365→            catch(e) { return false; }
 366→        });
 367→
 368→        // Si c'est un tout nouveau projet et qu'on a atteint la limite MENSUELLE
 369→        // Les anciens projets ne comptent pas dans cette limite
