 404→            db.update(0, updated);
 405→            return [updated, ...prev.slice(1)];
 406→          });
 407→          setAnalysisData(prev => prev ? { ...prev, preGenerated } : prev);
 408→          setMegaStatus('completed');
 409→        } else {
 410→          setMegaStatus('failed');
 411→        }
 412→      }).catch(() => setMegaStatus('failed'));
 413→
