 460→            ...prev,
 461→            generatedSolutions: {
 462→                ...(prev.generatedSolutions || {}),
 463→                [recommendationId]: solutionWithMeta
 464→            }
 465→        };
 466→    });
 467→
 468→    // We need to find the index in the history to update the DB
 469→    setHistory(prevHistory => {
 470→        const index = prevHistory.findIndex(item => item.timestamp === analysisId);
 471→        if (index !== -1) {
 472→            const updatedItem = {
 473→                ...prevHistory[index],
 474→                generatedSolutions: {
 475→                    ...(prevHistory[index].generatedSolutions || {}),
 476→                    [recommendationId]: solutionWithMeta
 477→                }
 478→            };
 479→            // Persist using db service
 480→            const newHistory = [...prevHistory];
 481→            newHistory[index] = updatedItem;
 482→            // Note: calling db.update relies on index which matches prevHistory order if initialized from DB
 483→            db.update(index, updatedItem);
 484→            return newHistory;
